import React, { useState } from 'react';

function Gallery() {
  const [selectedImage, setSelectedImage] = useState(null);

  // Gallery images - Add your images here
  const galleryImages = [
    {
      id: 1,
      title: 'Design Project 1',
      category: 'UI/UX',
      image: '🎨',
      description: 'Modern dashboard design'
    },
    {
      id: 2,
      title: 'Photography 1',
      category: 'Photography',
      image: '📸',
      description: 'Portrait photography'
    },
    {
      id: 3,
      title: 'Graphic Design 1',
      category: 'Graphic',
      image: '🖼️',
      description: 'Brand identity design'
    },
    {
      id: 4,
      title: 'Web Design 1',
      category: 'Web',
      image: '🌐',
      description: 'Website interface'
    },
    {
      id: 5,
      title: 'Illustration 1',
      category: 'Illustration',
      image: '✨',
      description: 'Digital illustration'
    },
    {
      id: 6,
      title: 'Motion Design 1',
      category: 'Motion',
      image: '🎬',
      description: 'Animation project'
    },
    {
      id: 7,
      title: 'Product Design 1',
      category: 'Product',
      image: '🛍️',
      description: 'Product interface'
    },
    {
      id: 8,
      title: 'Concept Art 1',
      category: 'Art',
      image: '🎭',
      description: 'Concept artwork'
    },
    {
      id: 9,
      title: 'Brand Design 1',
      category: 'Branding',
      image: '🏷️',
      description: 'Logo and branding'
    },
  ];

  return (
    <div className="bg-white">
      {/* Gallery Header */}
      <section className="py-8 md:py-12 max-w-7xl mx-auto px-4">
        <div className="mb-12">
          <p className="text-sm uppercase tracking-widest text-gray-600 mb-2">Visual Work</p>
          <h1 className="text-5xl md:text-6xl font-black text-gray-900 mb-6">Gallery</h1>
          <p className="text-lg text-gray-600 max-w-2xl">
            A collection of my design work, photography, and creative projects. Each piece represents my approach to solving visual problems and creating meaningful experiences.
          </p>
        </div>

        {/* Gallery Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {galleryImages.map((item) => (
            <div
              key={item.id}
              onClick={() => setSelectedImage(item)}
              className="group cursor-pointer"
            >
              <div className="bg-gray-100 border-2 border-gray-200 aspect-square rounded-sm flex items-center justify-center mb-4 hover:border-gray-900 transition duration-300 overflow-hidden">
                <div className="text-8xl group-hover:scale-110 transition duration-300">
                  {item.image}
                </div>
              </div>
              <h3 className="font-bold text-gray-900 text-lg mb-1">{item.title}</h3>
              <p className="text-sm uppercase tracking-widest text-gray-600 mb-2">{item.category}</p>
              <p className="text-gray-600">{item.description}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Lightbox Modal */}
      {selectedImage && (
        <div
          className="fixed inset-0 bg-black bg-opacity-75 z-50 flex items-center justify-center p-4"
          onClick={() => setSelectedImage(null)}
        >
          <div
            className="bg-white rounded-sm max-w-4xl w-full relative"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Close Button */}
            <button
              onClick={() => setSelectedImage(null)}
              className="absolute top-4 right-4 text-gray-900 hover:text-gray-600 z-10"
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>

            {/* Modal Content */}
            <div className="p-8 md:p-12">
              <div className="flex flex-col md:flex-row gap-8">
                {/* Image */}
                <div className="flex-1 flex items-center justify-center bg-gray-100 rounded-sm aspect-square">
                  <div className="text-9xl">{selectedImage.image}</div>
                </div>

                {/* Details */}
                <div className="flex-1 flex flex-col justify-center">
                  <p className="text-sm uppercase tracking-widest text-gray-600 mb-2">
                    {selectedImage.category}
                  </p>
                  <h2 className="text-4xl font-black text-gray-900 mb-4">
                    {selectedImage.title}
                  </h2>
                  <p className="text-lg text-gray-600 mb-6 leading-relaxed">
                    {selectedImage.description}
                  </p>
                  <div className="border-t border-gray-200 pt-6">
                    <p className="text-sm text-gray-500">
                      Project ID: #{selectedImage.id.toString().padStart(3, '0')}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Gallery;
